var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"외곽 호위라인 격파!","JPN":"外郭の護衛部隊を撃破！","ENG":"The line of defense in the perimeter has been destroyed.","TWN":"週邊警衛線已擊破！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"전령조 및 유선 통신망 우선 격파 확인.","JPN":"伝令組及び有線通信網の優先撃破を確認。","ENG":"Messenger units eliminated; all the wired communication devices have been destroyed.","TWN":"傳令兵小隊和有線通信網確認已優先擊破。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"이제 남은 건 비숍 본인과 소규모 근접 호위대뿐이야.","JPN":"残るは、ビショップ本人と小規模な護衛部隊のみ。","ENG":"All there's left are Bishop and a small number of her personal guards.","TWN":"現在只剩下大主教本人和她身邊的貼身保鑣了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"좋아.","JPN":"よーし。","ENG":"Good.","TWN":"好，"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"이제 최종 목표까지 한 걸음만 남았어.","JPN":"最終目標まであと一歩。","ENG":"We're only one step away from our final goal.","TWN":"現在離最終目標只剩下一步了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"힘들겠지만 빠르게 정비해서 단숨에 몰아친다.","JPN":"大変だと思うけど、速やかに態勢を整えて一気に攻め立てよう。","ENG":"I know you're tired, but brace yourselves. We're pushing through.","TWN":"雖然情況很艱難，但我們得迅速整頓，一鼓作氣完成任務。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......왜 이렇게 서두르는 거야?","JPN":"……どうしてここまで急ぐ必要があるわけ？","ENG":"Why are you so hasty?","TWN":"……我們為什麼要這麼急？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"누가 쫓아오기라도 해?","JPN":"誰かに追いかけられてるわけでもないのに？","ENG":"There's no one following us.","TWN":"會有人追過來嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"당연히 서둘러야지!","JPN":"急いで当然よ！","ENG":"Of course I'm hasty!","TWN":"當然要快啊！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"너희들이 이 좌표에 도달한 후로 시간이 얼마나 흘렀는지 알기나 해?","JPN":"あなたたちがこの座標に着いてから、どれだけの時間が過ぎたかわかってる？","ENG":"Do you have any idea how much time has passed since you arrived here?","TWN":"妳知道從你們達到這個座標後，已經過了多少時間嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"아무리 정보 전달망을 교란하고 있다고 해도 한계가 있어.","JPN":"敵の情報伝達網を撹乱させているとはいえ、限界はあるのよ。","ENG":"We can only do so much by disturbing their lines of communication.","TWN":"就算我們有在干擾資訊通訊網，但還是有極限的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"언제 간부들이 나타나도 이상하지 않다고.","JPN":"いつどこで幹部が現れてもおかしくないんだから。","ENG":"The officers could show up anytime now.","TWN":"幹部隨時會出現也不奇怪啊。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"나이트라면...... 어떻게든 시간이라도 끌어보겠지만......","JPN":"現れるのがナイトなら……どうにか時間稼ぎはできるかもしれないけど……","ENG":"If it's Knight, we might be able to buy time,","TWN":"騎士的話……我還可以試著拖一點時間……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"만약 퀸이 나타나기라도 한다면 이 작전은 그걸로 끝이야.","JPN":"もしもクイーンだったら、この作戦はそこで即終了よ。","ENG":"but if Queen shows up, that's the end of this operation.","TWN":"但要是女皇出現的話，這個作戰就完了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"퀸이라는 녀석이 그렇게 강해......?","JPN":"クイーンとやらは、そんなに強いの……？","ENG":"Exactly how strong is Queen?","TWN":"那個叫女皇的人這麼強嗎……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"네가 이렇게 자신 없는 말을 하는 건 처음 보는 것 같은데......","JPN":"あんたがそこまで弱気なことを言うのは初めてかも……","ENG":"I've never heard you sound so concerned about an enemy.","TWN":"妳好像還是第一次說出這麼沒自信的話呢……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 뭐야. 그 기분 나쁜 눈빛은?","JPN":"な、何よ、その冷たい眼差しは。","ENG":"W-what? What's that look?","TWN":"幹、幹嘛。這個讓人不舒服的眼神？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"아니, 그냥. 한심한 건 너인데 왜 내가 부끄러워해야 하는 건가 싶어서.","JPN":"いや、どうしてこんなにもわからず屋なのか、情けなくなってきてね。","ENG":"Oh, I was just wondering. Why should I be the embarrassed one when you are the pathetic one?","TWN":"沒有，可悲的明明是妳，為什麼是我要覺得丟臉啊？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"리플레이서 같은 테러 조직이 유지되기 위한 제 1조건이 뭐라고 생각해?","JPN":"リプレイサーのようなテロ組織を保つための第1条件は何だと思う？","ENG":"What do you think is the first rule of running a terrorist organization like the Replacer Syndicate?","TWN":"妳覺得要維持克隆集團這種恐怖組織，最重要的條件是什麼嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 글쎄......? 뭔데?","JPN":"さ、さあ……？　なんだろう？","ENG":"Uh... I'm not sure... What is it?","TWN":"呃，這個……是什麼？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"바로 직접적인 폭력 수단, 즉 힘이야.","JPN":"直接的な暴力、つまり武力だよ。","ENG":"It's a direct exhibition of force. In other words, violence.","TWN":"就是直接的暴力手段，也就是力量。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"적을 공포에 떨게 만들고 배신자를 처단하고 조직원이 감히 의문을 품지 못하게 만드는 압도적인 힘.","JPN":"敵を恐怖に震え上がらせ、裏切り者は始末し、\\n組織メンバーに絶大な信頼感を与える、圧倒的な力。","ENG":"They use violence to make enemies tremble, punish traitors, and keep the members in line.","TWN":"讓敵人瑟瑟發抖、除掉叛徒、使組織成員不敢質疑的壓倒性力量。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"리플레이서 5대 간부라는 것도 웃기는 소리야.","JPN":"5大リプレイサー幹部っていうのも笑わせるわ。","ENG":"The five officers of the Replacers? What a joke.","TWN":"所謂克隆集團5大幹部都挺搞笑的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"설립자인 킹을 제외하면 나머지 간부들은 사실상 퀸이 발굴하고 키워낸 녀석들이라고.","JPN":"設立者のキングを除けば、残りの幹部は事実上、クイーンが発掘して育てた奴らだからね。","ENG":"Except for King, the founder, all the rest were actually discovered and reared by Queen.","TWN":"除了創立者的帝皇之外，剩下的幹部實際上，都是女皇發掘並培養出來的人。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"반란이나 항명 따위는 전혀 걱정하지 않고 자신과 동격의 간부들을 키워내는 그 자신감이 대체 어디서 나온다고 생각해?","JPN":"反逆などをまったく気にせず、自分と同格の幹部を育成する。その自信はどこから来てると思う？","ENG":"Why do you think Queen can keep discovering talents and place them in officer positions without worrying about rebellion or disobedience?","TWN":"妳覺得她到底哪來的自信，完全不擔心叛亂和反抗，刻意培育出與自己同級的幹部？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"다른 간부들이...... 전부 덤벼들어도 이길 수 있으니까?","JPN":"他の幹部が……全員かかってきても、勝てる自信があるから？","ENG":"Because she's stronger than all of the others combined?","TWN":"因為其他幹部……一起上也打不贏她？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"맞아.","JPN":"そのとおり。","ENG":"That's right.","TWN":"對。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"리플레이서 융합체와 침식체 등급의 1:1 비교가 정확하지는 않지만......","JPN":"リプレイサー融合体と侵食体ランクの比較が正確とは言えないけれど……","ENG":"We really can't compare a Replacer hybrider to a C.O. one for one,","TWN":"把克隆融合體和侵蝕體分級做1:1的比較雖然不太準確……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"각국 정보부에서 리플레이서 퀸은 4종 침식체와 동급의 위험요소로 평가 받고 있다고.","JPN":"各国の情報局でリプレイサー・クイーンは、第4種侵食体と同等の危険因子として評価されてるの。","ENG":"but intelligence agencies all over the world estimate that Replacer Queen is as dangerous as a Category 4 C.O.","TWN":"但在各國情報部的評價中，女皇和4級侵蝕體同樣危險。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"4, 4종......?!","JPN":"だ、第4種だって……！？","ENG":"C-Category 4?","TWN":"4，4級……？！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"이쯤 설명했으면 너도 알아들었겠지?","JPN":"そろそろわかってきたでしょ？","ENG":"So, I assume you now understand why I've become all edgy","TWN":"說到這裡，妳應該也明白了吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"내가 왜 퀸의 이야기만 나오면 물 맞은 고양이처럼 경기를 일으키는지......","JPN":"どうして私が急いでいるのか……","ENG":"like a cat that heard a dish break when someone brings up Queen.","TWN":"為什麼聽到女皇的事情，我就像驚弓之鳥一樣……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"내 생각엔...... 힐데 소대장이라고 해도 정면으로 싸워 이기는 건 무리일 거야.","JPN":"たぶん……ヒルデ小隊長でも真っ向勝負では勝てないと思う。","ENG":"Personally, I don't think even Commander Hilde could defeat her head on.","TWN":"根據我的推測……就算是希爾德小隊長，正面對決都無法取勝。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"대충은 알아들었어.","JPN":"言いたいことは、だいたいわかったよ。","ENG":"I get what you mean.","TWN":"我大概明白了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러고 보니 그 퀸이라는 녀석과 개인적인 친분이라도 있는 거야?","JPN":"そういえば、そのクイーンとやらとは何か個人的な繫がりでもあるの？","ENG":"By the way, are you personally acquainted with Queen?","TWN":"話說，妳和那個叫女皇的人好像有什麼關係？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"너와는 꽤 잘 알고 있는 눈치던데......?","JPN":"あんたのこと、よくわかってるような素振りを見せてたけど……？","ENG":"She seemed to know you pretty well.","TWN":"妳好像非常瞭解她的樣子……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"뭐, 언젠가는 알게 될 내용이니까 지금 미리 이야기해주는 게 나을지도 모르겠네.","JPN":"まあ、いつかはわかる日が来るだろうから、今ここで教えたほうがいいか。","ENG":"Well, you're going to find out eventually. I might as well tell you now.","TWN":"嘛，反正總要知道的，事先告訴妳說不定會比較好。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"우리가...... 알트 소대가 리플레이서 출신이라는 건 알고 있지?","JPN":"私たち……アルト小隊がリプレイサー出身なのは知ってるよね？","ENG":"You know that we, the ALT Squad, were once in the Syndicate, don't you?","TWN":"我們……阿爾特小隊是克隆集團出身的，這件事妳知道吧？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐...... 듣긴 했어.","JPN":"まあ……聞いてはいるけど。","ENG":"So I've heard.","TWN":"嗯……這我有聽過。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"정확히 말하면 우린 리플레이서가 아닌 리플레이서 실험체 출신이야.","JPN":"厳密に言うと、私たちはリプレイサーじゃなくて、リプレイサー実験体出身なの。","ENG":"To be precise, we weren't exactly Replacers. We were test subjects.","TWN":"正確來說，我們不是克隆集團，而是克隆集團實驗體出身。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"실험체......?","JPN":"実験体……？","ENG":"Test subjects?","TWN":"實驗體……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"내가 가진 첫 번째 기억은...... 차가운 실험대 위에 누워 있는 내 모습이었어.","JPN":"私が持ってる最初の記憶は……冷たい実験台に横たわっている自分の姿。","ENG":"The first memory I have is lying on the cold lab table.","TWN":"我最初的記憶……是我躺在冰冷實驗臺上的樣子。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"내가 누구였는지, 어디에 살았는지, 원래 이름은 뭐였는지......","JPN":"私は誰なのか、どこに住んでいたのか、元々の名前はなんだったのか……","ENG":"Who I was, where I came from, what my real name was...","TWN":"我是誰、住在哪裡、原本的名字叫什麼……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그런 기억은 아무것도 없어.","JPN":"そんな記憶は何もないの。","ENG":"I couldn't remember anything.","TWN":"什麼記憶也沒有。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무슨...... 설마 납치라도 당한 거야?","JPN":"それはどういう……まさか、さらわれたとか？","ENG":"No... Did they kidnap you or something?","TWN":"什麼……該不會是被綁架了吧？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"몰라. 실험의 부작용인지 뭔지, 그 이전의 기억은 아무것도 나지 않으니까.","JPN":"わからない。実験の副作用なのか、それ以前の記憶がまったくないの。","ENG":"I don't know. I don't know if it's the side effects of the experiment, but I lost all my previous memories.","TWN":"不知道。不知道是因為實驗的副作用還是什麼，那之前的記憶完全想不起來。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"한때는 부모님을 찾고 싶다는 마음도 있었지만...... 그런 희망은 버린 지 오래야.","JPN":"一時は実の親を探したい気持ちもあったけど……そんな希望はとっくに捨てたわ。","ENG":"I once thought I wanted to find my parents, but I gave up on that a long time ago.","TWN":"以前，我也想過要去找自己的父母……但這個希望也放棄很久了。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"어쨌든 그곳은 실험실이자, 일종의 선별 장소였어.","JPN":"とにかく、そこは実験室で、ある種の選別場所でもあったの。","ENG":"Anyway, the place was a lab, and at the same time a testing ground.","TWN":"不管怎樣，那裡既是實驗室，還是一種選拔的場所。"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선별?","JPN":"選別？","ENG":"Testing ground?","TWN":"選拔？"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그래, 과목도 다양했어.","JPN":"そう、色んなテストがあったのよ。","ENG":"Yes, of various things.","TWN":"沒錯，篩選的科目也很多樣。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"간단한 IQ 테스트부터 약물검사, 전투 훈련, 생존 경쟁까지......","JPN":"簡単なIQテストから、薬物検査、戦闘訓練、勝ち抜きテストまで……","ENG":"We did simple IQ tests, chemical experiments, combat training, survival free-for-alls...","TWN":"從簡單的IQ測試，到藥物檢測、戰鬥訓練，到生存競爭……"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"새, 생존 경쟁?","JPN":"か、勝ち抜きテスト？","ENG":"S-survival free-for-alls?","TWN":"生、生存競爭？"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"설마 같은 방 안에 몰아넣고 서로 죽이라고 시켰다거나......","JPN":"まさか、同じ部屋に閉じ込めて、殺し合いをさせたとか？","ENG":"Did they put you all in the same room and make you kill each other?","TWN":"難道是在同一個房間裡玩大逃殺嗎……"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"무슨 말도 안 되는 소리야? 무협지를 너무 많이 본 것 같은데?","JPN":"そんなわけないでしょ、映画の見すぎじゃないの？","ENG":"What are you talking about? You've been watching too many movies.","TWN":"這是什麼鬼話？武俠小說看太多了吧？"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"사춘기도 안 지난 애들에게 그런 짓을 했다간 선별이고 뭐고 심리 쇼크로 자살하기 십상일걸?","JPN":"思春期すら迎えてない子どもにそんなことさせてたら、\\n選別どころか、トラウマで自殺する子が続出するわよ。","ENG":"We're talking about prepubescent kids here. Something like that would have destroyed their minds beyond recovery.","TWN":"讓連青春期都還沒到的小孩做那種事，還做什麼選拔，早就因為心理創傷而自殺了吧？"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"하지만 뭐...... 아주 틀린 말도 아니지. 그때의 훈련 과정은......","JPN":"でもまあ……あながち間違ってもいないかもね。当時の訓練過程は……","ENG":"But... In a way, you're not entirely wrong. The training was...","TWN":"但是……妳說得也沒有錯太多。當時的訓練課程……"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"......아니, 이 이야긴 그만 할래.","JPN":"……いや、この話はここまでにしましょう。","ENG":"No, I don't want to talk about it anymore.","TWN":"……不。不說這個了。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"어쨌든 선별 인원들은 몇 개의 조별로 활동했는데,","JPN":"とにかく、選別されたメンバーはいくつかのチームに分かれて活動したんだけど、","ENG":"Anyway, we were divided in groups,","TWN":"總之就是選拔人員分為幾個小組。"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그곳에서 날 담당한 선별감독관이......","JPN":"そこで私の担当になった選別監督官が……","ENG":"and Replacer Queen was the overseer","TWN":"在那裡負責我的選拔督察員……"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"바로 리플레이서 퀸이었어.","JPN":"まさにリプレイサー・クイーンだったの。","ENG":"that was in charge of my group.","TWN":"就是克隆．女皇。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런......!","JPN":"そんな……！","ENG":"What?","TWN":"怎麼會……！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"내 입으로 말하긴 그렇지만 선별 대상으로서의 내 성적은 꽤 괜찮은 편이었어.","JPN":"自分で言うのはあれだけど、選別メンバーとしての私の成績はかなり良い方だった。","ENG":"Though I say it myself, my grades there were pretty good.","TWN":"雖然這是我自己說的，但作為選拔對象，我的成績非常好。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"QUEEN_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"하지만 리플레이서 나이트 같은 머저리가 간부 후보생으로 뽑혀가는 와중에서도......","JPN":"だけど、リプレイサー・ナイトみたいなマヌケも幹部候補生に選ばれたっていうのに……","ENG":"But while morons like Replacer Knight were being picked out as officer candidates,","TWN":"但當克隆．騎士那樣的笨蛋被選為幹部候補的時……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"난 선별되지 못했지.","JPN":"私が選ばれることはなかった。","ENG":"I was still stuck in there.","TWN":"我卻沒被選上。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"아이들이 점점 줄어들면서...... ","JPN":"メンバーがだんだん減っていく中……","ENG":"The number of kids were decreasing, ","TWN":"孩子們越來越少……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"난 초조해졌어.","JPN":"私は焦りを感じるようになったの。","ENG":"and I was nervous.","TWN":"我開始焦急了起來。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"웃기는 이야기지만 그런 곳에서 몇 년을 지내고 나면 날 납치한 자들에 대한 분노보다, 인정받고 싶다는 경쟁심리가 생기게 되거든?","JPN":"おかしな話だけど、あんな場所で数年間暮らしてると、\\n自分をさらった奴らへの怒りよりも、認められたいという承認欲求のほうが強くなっていくのよ。","ENG":"It may sound ridiculous, but year after year, the anger I had toward them for kidnapping me faded away and a weird drive for competition started to fill my mind.","TWN":"說來好笑，在那裡待了幾年之後，比起對綁架我的人感到憤怒，我反而產生了想要獲得他們認可的競爭心理。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그래서 노력했어.","JPN":"だから、努力し続けたの。","ENG":"So I worked hard.","TWN":"所以我開始努力。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"잠도 자지 않고, 상처 입은 짐승처럼 주변에 가시를 세우면서......","JPN":"睡眠もとらず、傷ついた獣のように、周りをけん制しながら……","ENG":"I barely slept. I was like an injured animal trying to look as fierce as possible.","TWN":"我不睡覺，像受傷的動物一樣警戒著周圍……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"정말 죽을 힘을 다해 좋은 평가를 받기 위해 훈련에 매진했어.","JPN":"良い評価をもらうために、本当に死ぬ気で訓練に励んだわ。","ENG":"I did my damnedest to train myself, desperate to be in their favor.","TWN":"為了得到好的評價拼了命地訓練。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그러다가......","JPN":"そして……","ENG":"Then...","TWN":"然後……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOONSEO_KID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"최종 테스트인 팀 별 모의 전투에서...... 결국 팀원이 모두 당하고, 난 쓰러지고 말았지.","JPN":"最終テストである、チーム対抗の模擬戦闘で……\\nチームメンバー全員がやられ、私は倒れてしまったの。","ENG":"The day of mock combat, the final test, came, and all my teammates fell, just like I did.","TWN":"在最終測驗的小組模擬戰中……組員全被擊敗，而我也倒下了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"제대로 싸워 보지도 못했어.","JPN":"ろくに戦うこともできなかった。","ENG":"In fact, I never got a chance to fight.","TWN":"連好好戰鬥都沒辦法。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"쓰러진 원인이...... 어이없게도 과로로 인한 몸살이었거든.","JPN":"倒れた原因が……呆れることに、過労による体調不良だったのよね。","ENG":"I passed out before the test from all the stress and overwork.","TWN":"我倒下的原因……毫不意外的，是過勞引起的身體疼痛。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그때 선별 감독관...... 리플레이서 퀸이 내게 다가와서 말하더라고......","JPN":"その時、選別監督官……リプレイサー・クイーンが私に近づいてこう言ったの。","ENG":"Then the overseer, Replacer Queen, came up to me and said","TWN":"那個時候選拔督察員……克隆．女皇走過來對我說……"},"stage":{"bg":"MAINSTREAM_411010","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그렇게 마음만 급해서 자기자신을 채찍질 해봐야 바뀌는 건 아무것도 없다고.","JPN":"そんなに焦って自分を追い込んだって、何も変わりやしない。","ENG":"that I wouldn't be able to get anything by pushing myself too hard without a purpose.","TWN":"只是因為心急而鞭策自己的話，什麼都不會改變的。"},"stage":{"bg":"MAINSTREAM_411010","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"정말 인정 받고 싶다면 감독관인 자신이 아니라, 주위를 돌아보고 동료에게 인정받기 위해 노력하라고......","JPN":"本当に認められたいなら、監督官である自分じゃなくて、\\nまず周りの仲間に認められるために努力しなさいと。","ENG":"She said that I would need to try and earn faith and respect from my colleagues rather than trying to impress the overseer.","TWN":"真的想獲得認可的話，不是身為監察官的她，而是去環顧周圍，為了得到夥伴的認可而努力。"},"stage":{"bg":"MAINSTREAM_411010","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"하하, 국제적 테러리스트가 하는 말 치고는 너무 정론이라서 지금도 어이가 없다니까?","JPN":"はは、国際的なテロリストの発言にしてはあまりにも正論過ぎて、今でもわけがわからないよ。","ENG":"Can you believe that came from an internationally notorious terrorist?","TWN":"哈哈，國際恐怖分子說的話太有道理了，我到現在都還覺得很沒面子呢！"},"stage":{"bg":"MAINSTREAM_411010","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"야...... 그거......","JPN":"ちょっと……それって……","ENG":"Hey, is that...","TWN":"喂……那個……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"설마 그게 그때......?","JPN":"まさかあの時の……？","ENG":"That thing that you said back then... Was it about...","TWN":"難道那個是那時候的……？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그래. 그때 네게 말했던 아는 언니 이야기야.","JPN":"そう、あの時、あなたに話した知り合いのお姉ちゃんの話だよ。","ENG":"Yes. I was talking about Queen back then.","TWN":"沒錯。就是跟妳說過的那個認識的姐姐。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그때랑은 전혀 분위기가 다르잖아!","JPN":"あ、あの時の話とは状況が全然違うじゃない！","ENG":"Th-those two stories don't even sound like they're in the same genre!","TWN":"和、和那個時候感覺完全不一樣啊！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그랬나?","JPN":"そうかな？","ENG":"Do they?","TWN":"是嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"뭐, 없는 말을 지어내진 않은 것 같은데?","JPN":"でも、嘘はついてないよ？","ENG":"Well, it's not like I'm making things up.","TWN":"這應該不是我編造出來的啊？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니, 그게 무슨......","JPN":"はあ、何よそれ……","ENG":"You've got to be kidding me!","TWN":"不，這算什麼……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그리운 사람 이야기라며?!","JPN":"恋しい人の話じゃなかったの！？","ENG":"You said it was about someone you missed!","TWN":"不是說妳的思念之人嗎？！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 이야기의 어디가 그리운 사람에 대한 이야기야?!","JPN":"これのどこが、恋しい人の話なのよ！？","ENG":"Exactly which part of this story suggests that Queen's the one you missed?","TWN":"這哪裡是妳思念之人的事情了？！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"왜 그래? 내가 퀸을 얼마나 그리워했는데?","JPN":"なに言ってるの？　私がどれだけクイーンのことを想っていたか。","ENG":"Huh? Do you know how much I wanted to meet Queen again?","TWN":"怎麼了？我很想女皇啊？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"반드시 다시 만나서 그 빌어먹을 여자를 후회하게 만들어 주겠다고 몇 번이나 다짐했거든.","JPN":"必ずや再会して、あの女を後悔させてやるって何度も胸に誓ったわ。","ENG":"I was determined to face that damned wench again and make her beg for forgiveness!","TWN":"我一定會回來見她，讓那個該死的女人後悔，這些我提醒自己無數次了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"직접 싸워서 이길 수는 없겠지만......","JPN":"直接対決で勝つことはできなくても……","ENG":"I won't be able to take her down myself,","TWN":"雖然直接戰鬥沒辦法贏過她……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"적어도 그 여자의 진짜 목표가 뭐든 절대 이루어지지 않도록 죽을 힘을 다해서 방해하고, 또 방해해 주겠다고.","JPN":"彼女の真の目的が何であれ、決して達成はさせまいと、死ぬ気で絶対に阻止してやるんだと。","ENG":"but I'll at least be the biggest hassle in her life, the biggest pain in her neck, to keep her from achieving whatever it is that she's trying to do.","TWN":"但至少也要讓那個女人的真正目的無法實現，拚死也要阻止她，阻止這一切。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 뭐야?","JPN":"な、何なのよ？","ENG":"Huh?","TWN":"什、什麼啊？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"둘이 사이 좋았던 거 아니었어?","JPN":"二人は仲良しって流れじゃなかったの？","ENG":"It sounded like you liked her back then.","TWN":"你們兩個的關係不是很好嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"......나도 그렇게 착각했었지.","JPN":"……私もそう勘違いしてたよ。","ENG":"That's what I thought.","TWN":"……我原本也是這麼認為的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"패배한 팀원들을 추슬러서 간신히 와일드카드를 얻어내고......","JPN":"あの後、敗北したチームメンバーをなんとか取りまとめて、やっとの思いでワイルドカードを獲得した。","ENG":"At least until I picked up my teammates from despair, managed to win a wild card,","TWN":"當我們失敗的隊員重新振作，好不容易獲得了參賽名額……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"압도적인 전력 차의 우승팀과 재대결에서 승리한 다음......","JPN":"そして、圧倒的に強かった優勝チームとの再対決で勝利を収めたけど……","ENG":"won at the rematch against the formidable champions,","TWN":"並和戰力有壓倒性差距的隊伍再度對決，取得勝利之後……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"기쁜 얼굴로 달려간 나와 팀원들을 모조리 인자 추출기 안에 집어넣기 전까지는 말이야.","JPN":"歓喜の顔で駆け付けた私やチームメンバー全員は、ファクター抽出器に放り込まれたのよ。","ENG":"only to be shoved inside a Factor Extractor along with the rest of my teammates!","TWN":"我和隊員們全都高興地跑向她，接著我們卻全被抓進了因子萃取器裡……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......!!","JPN":"……！！","ENG":"......!!","TWN":"……！！"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"나중에 알게 된 사실이지만 난 선별되지 못한 게 아니었어.","JPN":"後から知ったけど、私は選別テストに落ちたわけじゃなかった。","ENG":"I found out later, but I was left there for a reason.","TWN":"雖然我之後才知道，我不是沒被選中。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"나와 함께 최종 테스트까지 도달한 아이들은 모두 얼터너티브 인자 이식용 실험체로 결정되어 있었던 거야.","JPN":"私と一緒に最終テストまでたどり着いたメンバーは、\\n全員がオルタナティブ・ファクター移植用の実験体になることが決まってたのよ。","ENG":"All the kids who made it to the end of the test were destined to be used as subjects in the Alternative Factor transplant experiments.","TWN":"而是和我一起通過最終測試的孩子們，全都被選為移植用的可替代因子試驗體。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼...... 어째서 너에게 그런 조언을 한 거야?","JPN":"だったら、なぜあんたにあんな助言をしたんだろう？","ENG":"Then why did she give you that advice?","TWN":"那……她為什麼要給妳那個建議？？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"글쎄? 아마도 승부에 대한 집착이나 동료애 같은 정신적 요소가 실험 데이터에 필요했나 보지.","JPN":"さあ？　わからないけど、勝負への執念や仲間想いのようなメンタル要素が実験データに必要だったのかもね。","ENG":"Who knows? Maybe she wanted to find out how mental factors like desire to win or comradeship affected performance for her research.","TWN":"誰知道呢，大概實驗資料需要對勝利的執著，和夥伴情誼這些精神要素吧。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그게 아니면 한치 앞도 못 보는 멍청이가 손바닥 위에서 춤을 추는 게 재미있었을 수도 있고.","JPN":"それとも、目前の危機にも気が付かないマヌケが、手のひらの上で躍らされるのが楽しかったのかも。","ENG":"Or, she was just having fun watching an idiot making a fool of herself.","TWN":"要不然就是喜歡把我們玩弄在股掌之間的感覺。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"뭐가 됐건 우리에게 그런 걸 고민할 틈 따윈 없었어.","JPN":"どっちにしろ、私たちにそんなことを考えてる暇はなかった。","ENG":"Whatever it was, we didn't have the luxury to think.","TWN":"不管怎樣，我們都沒有空去管那些事。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그날부터 바로 하루에 10시간이 넘게 추출기에 들어가 있으면서 온몸이 새로 만들어지는 고통을 겪어야 했거든.","JPN":"その日から、一日10時間以上、抽出器のなかで全身が\\n作り変えられるような苦しみに耐えなければならなかったからね。","ENG":"Since that very day, we had to spend over 10 hours a day in an Extractor, suffering pain from physical reconstruction.","TWN":"那之後的每一天，我們都在因子萃取器裡待10小時以上，體會身體重新被塑造的痛苦。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그 와중에 겪어야 하는 39도가 넘는 고열이나 각종 조직 괴사 같은 부작용은 덤이고.","JPN":"おまけに、39度以上の高熱や様々な体内組織が壊死するような副作用もついてきた。","ENG":"Our fever spiked over 39 degrees Celsius, and our skin tissues started to die.","TWN":"在這個過程中，還附帶超過39度的高溫和各種組織壞死的副作用。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"1차 실험이 끝났을 때, 살아남은 적성체는 우리 네 명뿐이었어.","JPN":"第1次実験が終わった後、生き残った適性体は私たち4人だけだったの。","ENG":"When the first experiment was over, us four were the only survivors.","TWN":"第一次實驗結束後，活下來的適性體就我們四個人。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래서 도망친 거야?","JPN":"それで、逃げ出したの？","ENG":"Was that when you ran away?","TWN":"所以你們就逃跑了？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"다행히 그때쯤 리플레이서 내부에서 작은 반란 사건이 벌어졌었어.","JPN":"幸いなことに、その頃リプレイサーの中で小さな反乱が起こったの。","ENG":"Fortunately, there was a small-scale revolt inside the Syndicate.","TWN":"幸運的是，那個時候克隆集團內部發生了小叛亂。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SIREN"},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"자세한 건 모르지만 이안...... 뭐라고 하는 시니어 연구원이 고위 침식체를 연구소 내부에 풀어놓은 것 같던데......","JPN":"詳しいことはわからないけど、イアン……なんとかというシニア研究員が、\\n高位侵食体を研究所の中に解放したらしい……","ENG":"I don't remember all the details, but this senior researcher named Ian something released a high-category C.O. inside the lab.","TWN":"具體的我也不清楚，叫伊恩……什麼的資深研究員好像把高等侵蝕體放到研究院內部……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그 틈을 타서 우리도 탈출에 성공할 수 있었지.","JPN":"その隙に、私たちは脱出できたの。","ENG":"We took advantage of it and escaped during the commotion.","TWN":"趁這個機會，我們才能夠成功逃脫的。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이안......? 혹시 이안 메이슨이라는 이름 아니었어?","JPN":"イアン……？　もしかして、イアン・メイソンって名前じゃない？","ENG":"Ian? Was his last name Mason?","TWN":"伊恩……？該不會是叫伊恩．梅森嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"글쎄......? 그랬던 것 같기도 하고......","JPN":"さあ……？　そんな気もするけど……","ENG":"I don't know. Maybe it was.","TWN":"這……？好像是……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"잘 모르겠어, 혹시 아는 사람이야?","JPN":"よくわからない。もしかして知り合いなの？","ENG":"I can't be sure. Why? Do you know him?","TWN":"我也不清楚，妳該不會認識他吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 아니야. 그 뒤엔 어떻게 됐는데?","JPN":"い、いや、その後はどうなったの？","ENG":"I-it's nothing. So what happened next?","TWN":"啊，沒有。那之後怎麼樣了？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"탈출하고 나서, 한동안은 추적당할까 봐 거지꼴로 숨어 살았지.","JPN":"脱出直後しばらくの間は、追跡を警戒して、ホームレス同然の逃亡生活をしてたわ。","ENG":"After we escaped, we lived in hiding for some time.","TWN":"逃出來之後，我們因為害怕被追捕，有很長一段時間都假扮成乞丐躲躲藏藏。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"하지만 그런 식으로는 희망이 없다는 걸 깨달았어.","JPN":"でも、そのままじゃ望みがないことに気づいたの。","ENG":"But it didn't take long before we realized it was meaningless.","TWN":"但是，我們察覺到那樣是沒有希望的。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"언젠가는...... 리플레이서가 우릴 찾아낼 테니까.","JPN":"いずれは……リプレイサーが私たちを見つけるだろうから。","ENG":"It was only a matter of time before the Syndicate found us.","TWN":"因為總有一天……克隆集團會找到我們的。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그래서 살아남기 위해, 힘을 기르기 위해,","JPN":"だから、生き残る力をつけるために、","ENG":"So we started our mercenary business from scratch.","TWN":"所以，為了活下來，為了積蓄力量……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"간신히 팀을 만들고 밑바닥부터 용병일을 시작했어.","JPN":"なんとかチームを作って、傭兵として底辺の仕事から始めたの。","ENG":"We did it to survive—to build up strength to defend ourselves.","TWN":"我們艱難地創建了隊伍，從最底層開始做起了傭兵……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그 후에는...... 잘 알겠지?","JPN":"そこからは……知ってのとおりよ。","ENG":"And... you know the rest.","TWN":"之後的事情……妳應該都知道了吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래서...... 정식 라이선스를 따는 데 그렇게 집착한 건가?","JPN":"だから……正式ライセンスにそこまでこだわってたの？","ENG":"Is that why you were so obsessed with getting the official license?","TWN":"所以……為了獲得正式許可證，你們才那麼執著嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"맞아. 관리국의 정식 라이선스가 있으면 생각보다 많은 지원을 받을 수 있어.","JPN":"うん。管理局の正式ライセンスがあれば、想像以上に豊富な援助を受けることができるの。","ENG":"Correct. There are more benefits to being a licensed TASKFORCE team than you'd think.","TWN":"沒錯。有了管理局的正式許可證，就可以獲得比想像中還要多的援助。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"운이 좋으면...... 구 관리국의 고유 무장을 얻을 수도 있고.","JPN":"運が良ければ……旧管理局の固有武器も得られるし。","ENG":"If you're lucky, you could get your hands on one of the Unique Gears of the Old Administration.","TWN":"運氣好的話……還有可能得到舊管理局的專屬裝備。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"뭐가 됐든 우릴 찾는 리플레이서 놈들을 엿 먹이는데 도움이 됐겠지.","JPN":"いずれにしても、私たちを追いかけてくるリプレイサーどもを懲らしめるのに役立つでしょうね。","ENG":"It would have helped us screwing things up for the Replacers, one way or another.","TWN":"不管是什麼，都能幫助我們對付克隆集團的傢伙們。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"대체......","JPN":"いったい……","ENG":"That's insane...","TWN":"到底……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"대체 그 얼터너티브 인자인가 하는 게 뭔데 그런 끔찍한 실험을 하는 거지?","JPN":"いったい、オルタナティブ・ファクターって、何なの？　どうしてそこまで恐ろしい実験をするんだろう。","ENG":"What about the Alternative Factor is so important that they need to carry out such horrible experiments?","TWN":"可替代因子到底是什麼，克隆集團竟然要做那麼殘忍的實驗？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"글쎄? 사실은 나도 잘 몰라.","JPN":"さあね、私も実態はよくわかってないの。","ENG":"Well, I'm not entirely sure.","TWN":"誰知道？其實我也不清楚。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"일반적인 리플레이서 인자와 프로그레시브 인자 중간 정도의 힘을 제공하고......","JPN":"通常のリプレイサー・ファクターとプログレッシブ・ファクターの中間程度の力を与え……","ENG":"All I know is that the magnitude of the power it awakens lies somewhere between normal Replacer Factors and Progressive Factors,","TWN":"可替代因子提供了一般的克隆因子和可操控因子中等程度的力量……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"약간의 부작용은 있지만 유지보수를 위한 추가적인 리플레이서 인자를 투여하지 않아도 붕괴하지 않는 안정적 변이인자라는 것 정도......","JPN":"若干の副作用はあるけど、メンテナンスのためにリプレイサー・ファクターを追加で\\n投与しなくても壊れることはない、安定的な変異因子だということくらいしか……","ENG":"and that it's a stable type of Mutation Factor with minor side effects, which doesn't need additional Replacer Factor injections to stay active.","TWN":"雖然有一點副作用，但不需要服用維持用的追加克隆因子，身體也不會崩壞，是信賴度很高的變異因子……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"하지만 뭐가 됐든 상관없어.","JPN":"まあ、中身はどうだって良いの。","ENG":"What it is doesn't matter anymore.","TWN":"但不管那是什麼，我都不在乎。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_PRIDE"}}}},{"id":"L2_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"바로 여기서 리플레이서의......","JPN":"まさにここで、リプレイサーの……","ENG":"This is where it all ends.","TWN":"就在這裡，克隆集團……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그 여자의 최종 목적을 소각로에 처넣어서 불태워버릴 생각이니까.","JPN":"あの女の最終目的を焼却炉に放り込んで燃やしてしまうつもりだから。","ENG":"I'm going to shove the ultimate goal of the Replacers in the flames and burn it to ashes.","TWN":"那個女人的最終目的，要被我們扔到焚化爐裡燒掉。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"알겠지? 네가 바로 그 불을 지를 성냥이라고.","JPN":"わかった？　つまりあなたが、火をつけるためのマッチ役になるのよ。","ENG":"Get it? And you're the match that's going to start the fire.","TWN":"懂了嗎？妳就是那根點火的火柴。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"만약 실수하기라도 하면......","JPN":"もし失敗でもしたら……","ENG":"If you were to make a mistake,","TWN":"要是失敗了……"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"......난 아주 실망할 거야.","JPN":"……私はすごく失望すると思う。","ENG":"I'd be very disappointed.","TWN":"……我會很失望的。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_LANCE","text":{"KOREA":"그러니까 힘내, 유미나.","JPN":"だから、頑張って、ヤナギ・ミナ。","ENG":"So I need you to focus, Yoo Mina.","TWN":"所以請妳加油，劉米娜。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......알았어.","JPN":"……わかった。","ENG":"I will.","TWN":"……知道了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_REPLACER_NULL_LANCE","face":"UNIT_IDLE"}}}}]`);export{e as default};